<script>
if(1 == 1){
$('.H1text').addClass('animated null fadeInDown');
}
else if(1 == 2){
$('.H1text').hover(function(){
  $(this).toggleClass('animated null fadeInDown')
});
}
else if(1 == 3){
$('.H1text').click(function(){
  $(this).toggleClass('animated null fadeInDown')
});
}
else if(1 == 4){
    $('.H1text').waypoint(function() {
    $('.H1text').addClass('animated null fadeInDown')
}, {offset: '100%'});
}
else if(1 == 5){
    $('.H1text').fadeOut();
    $('.H1text').waypoint(function() {
    $('.H1text').fadeIn(0, "linear")
    $('.H1text').addClass('animated null fadeInDown')
}, {offset: '100%'});
}
else if(1 == 6){
    $('.H1text').waypoint(function() {
    $('.H1text').fadeOut(0, "linear")
    $('.H1text').addClass('animated null fadeInDown')
}, {offset: '100%'});
}
else if(1 == 7){
    $('.H1text').fadeOut();
    $('.H1text').waypoint(function() {
    $('.H1text').addClass('animated null fadeInDown')
}, {offset: '100%'})
    $('.H1text').fadeIn(0, "linear")
    $('.H1text').fadeOut(0, "linear");
}
else if(1 == 8){
    $('.H1text').fadeOut();
    $('.H1text').waypoint(function() {
    $('.H1text').fadeToggle(0, "linear")
    $('.H1text').addClass('animated null fadeInDown')
}, {offset: '100%'});
}
else{
window.onload = function() {
$('.H1text').addClass('animated null fadeInDown');
};
}
</script>

